#include<cstdio>
#include<vector>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
#define grep(b,c) for(int c(head[b]);c;c=nxt[c])
typedef long long LL;const int N=5e4+10,M=2e5+10;
inline LL read()
{
	LL res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
template<typename T> inline T max(const T&x,const T&y){return x<y?y:x;}
int head[N],des[M],nxt[M],cgt,n,m,d;bool vis[N];LL w[N],val[M],P[70];
inline void ins(LL z,int x,int y)
{
	nxt[++cgt]=head[x];des[head[x]=cgt]=y;val[cgt]=z;
	nxt[++cgt]=head[y];des[head[y]=cgt]=x;val[cgt]=z;
}
inline void Ins(LL x){drep(62,0,i){if(!(x>>i))continue;if(!P[i]){P[i]=x;return;}else x^=P[i];}}
inline void dfs(int u=1,LL W=0)
{
//	printf("dfs %d %lld\n",u,W);
	w[u]=W;vis[u]=true;grep(u,i)
	{
		int v=des[i];if(!vis[v])dfs(v,W^val[i]);
		else Ins(w[u]^w[v]^val[i]);
	}
}
int main()
{
	n=read();m=read();rep(1,m,i)ins(read(),read(),read());
	dfs();drep(62,0,i)w[n]=max(w[n],w[n]^P[i]);printf("%lld\n",w[n]);
}
